import pika
import subprocess
import sys

def callback(ch, method, properties, body):
    try:
        command = body.decode('utf-8')
        print(f" [x] Received and executing: '{command}'")
        # Execute the command using subprocess.run
        # For security, ensure that the commands coming from RabbitMQ are trusted.
        # Shell=True is used here as per the request, but can be a security risk.
        # Consider parsing and executing specific commands if security is a major concern.
        result = subprocess.run(command, shell=True, capture_output=True, text=True, check=True)
        print(f" [x] Command '{command}' finished.")
        print(f"    STDOUT:\n{result.stdout}")
        if result.stderr:
            print(f"    STDERR:\n{result.stderr}")
        ch.basic_ack(method.delivery_tag)
    except subprocess.CalledProcessError as e:
        print(f" [!] Command '{command}' failed with exit code {e.returncode}")
        print(f"    STDOUT:\n{e.stdout}")
        print(f"    STDERR:\n{e.stderr}")
        # Optionally, you might want to NACK the message or move it to a dead-letter queue
        # if the failure is transient or needs human intervention.
        # For now, we acknowledge to prevent reprocessing a failing command indefinitely.
        ch.basic_ack(method.delivery_tag)
    except Exception as e:
        print(f" [!] Error processing message: {e}")
        print(f" [!] Message body: {body.decode('utf-8', errors='ignore')}")
        # Acknowledge to prevent reprocessing a message that causes an unexpected error
        ch.basic_ack(method.delivery_tag)

def main():
    connection = None
    try:
        # Establish connection to RabbitMQ
        # Replace 'localhost' with your RabbitMQ server IP if it's not local
        connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
        channel = connection.channel()

        # Declare the queue. It's good practice for both producer and consumer to declare.
        # 'durable=True' makes sure the queue survives a RabbitMQ restart.
        channel.queue_declare(queue='job_queue', durable=True)

        # Set prefetch_count to 1 so that the consumer only gets one message at a time
        # and doesn't get another until it has acknowledged the previous one.
        channel.basic_qos(prefetch_count=1)

        print(' [*] Waiting for messages. To exit press CTRL+C')

        # Start consuming messages
        channel.basic_consume(queue='job_queue', on_message_callback=callback)
        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f" [!] Failed to connect to RabbitMQ: {e}")
        print(" [!] Please ensure RabbitMQ server is running and accessible.")
        sys.exit(1)
    except KeyboardInterrupt:
        print(' [x] Exiting consumer.')
    finally:
        if connection and connection.is_open:
            connection.close()

if __name__ == '__main__':
    main()